import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as c}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as p,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},b=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/d3e59a816b7d363a1c1b65231bc33cf8.html",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>我感觉依赖于互联网的话，视野就会变得狭窄。我已经对此深信不疑。就像对玩游戏的儿子说：「你会成为游戏脑的！」的母亲一样，互联网虽然看似广阔，但却令人感到局促，继续呆在那个狭窄的社区里的话，想法就会变得越来越僵硬。</p><p>这主要是由回声室（Echo chamber）现象和过滤泡（Filter bubble）现象的组合造成的。回声室……类似于在封闭空间向墙壁说话，自己的声音会回响回来，当在与自己兴趣相似的用户集结在一起的社区中发言时，相同的观点会聚集在一起，思维也会变得僵化。会使人相信「果然大家都这么想！」。然而，明明自己所看到的，只是世界的一小部分。</p><p>而过滤泡则是指通过算法和浏览历史，优先显示与自己兴趣相关的信息，导致自己的价值观逐渐被封闭在一个信息泡泡之中的现象。如果长时间在现代社会中持续使用互联网，那么无论如何都会或多或少地受到这两种现象的影响。</p><p>那样的话，不知不觉中，个人可能会被互联网吞噬，而自己的观点可能也会变得模糊不清，分不清是自己的观点还是互联网的观点和评论。我非常讨厌这种情况，所以最近每次想打开社交媒体或浏览器时，我都会先停下来打开Kindle。书籍的世界是由与互联网隔离的个人作者的思想和世界构建的，当我追踪文字和图像时，我可以集中精力在这个小世界中。此外，通过以连载的方式表达自己的想法，我也在记录着「当时的自己的思考」。即使我以后变成了互联网上的怪物，那时的自我仍然以文字的形式留存。</p><p>然而，说到这里，我认为「视野狭窄」未必总是不幸的。在与自己的感性类似的人群中聚集，享受不断流淌的自己感兴趣的信息和广告的世界，毫无疑问是愉快的。如果生活的重点是让自己快乐，那么以偏见的视角生活也没有什么不好。从中，也可以通过不断专注于某些事物来开辟道路。总之，目前通过一个智能手机就能访问全世界，这实在是不正常的情况，本来人类社会可以通过在本地与生活水平相似的人群中结交朋友来维持社会秩序，也没有问题。没有必要故意让自己与不同于自己、兴趣不相关的人，甚至可能会感到烦躁的人接触……。现代的便捷性也包括了用一次点击就能屏蔽不喜欢的事物。</p><p>最终，追求自己的幸福才是首要任务，如果不想被互联网吞噬，可以适度远离智能手机，与亲近的人在社区内欢聚也不错。当然，最好的方式是在不同情况下灵活运用这两种方式。能够在阴阳之间游刃有余的人最为强大。在思考这些事情的同时，我也认为最好的方式是不要过多地思考这些不必要的事情……。</p><hr><p><img src="'+c+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/3cd83f8b586fec253f0ca3a8b519ff4b.jpeg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/1926a50020c5cb2867ea6c37506faeb3.jpeg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【以梵高的《读小说的人》为灵感的钢笔】正如介绍所述，这支以梵高的画作为灵感的钢笔是我最喜欢的物品之一。一开始，我对钢笔并不怎么感兴趣，但却惊讶地发现它的写字感觉非常好。而且它的外观非常酷。外表酷炫是很重要的。因为当我写字的时候通常是一个人，所以有一支漂亮的钢笔作为伴侣在旁边陪伴着我，让我感到非常有信心。</p></blockquote>',10);function g(x,y){const l=a("ExternalLinkIcon"),n=a("RouterLink");return p(),_("div",null,[i(" more "),b,e("p",null,[t("原文链接："),e("a",h,[t("第22回／VSエコーチェンバー・フィルターバブル"),o(l)])]),e("blockquote",null,[u,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_21.html"},{default:m(()=>[t("【奈亚拉面壁自语】第21回｜独自旅行与孤独【230411】")]),_:1})])]),k])}const z=s(f,[["render",g],["__file","nyalra_kb_22.html.vue"]]);export{z as default};
